from collections import Counter
import heapq

class Solution:
    def minSumSquareDiff(self, nums1: List[int], nums2: List[int], k1: int, k2: int) -> int:
        diffs = [abs(a - b) for a, b in zip(nums1, nums2)]
        total_k = k1 + k2
        if total_k == 0:
            return sum(d * d for d in diffs)

        max_diff = max(diffs) if diffs else 0
        freq = Counter(diffs)
        heap = []
        for d in freq:
            heapq.heappush(heap, -d)

        while total_k > 0 and heap:
            current = -heapq.heappop(heap)
            if current == 0:
                break
            count = freq[current]
            next_val = current - 1
            if count <= total_k:
                total_k -= count
                del freq[current]
                freq[next_val] = freq.get(next_val, 0) + count
                if next_val > 0:
                    heapq.heappush(heap, -next_val)
            else:
                new_val = current - 1
                freq[current] -= total_k
                freq[new_val] = freq.get(new_val, 0) + total_k
                if freq[current] > 0:
                    heapq.heappush(heap, -current)
                if new_val > 0:
                    heapq.heappush(heap, -new_val)
                total_k = 0

        return sum(d * d * cnt for d, cnt in freq.items())
